# Fast: wraps test in a transaction, rolls back after
@pytest.mark.django_db
def test_user_creation(make_user):
    user = make_user()
    assert User.objects.count() == 1  # visible within transaction

# Slower: commits, then truncates — needed for signal/Celery tests
@pytest.mark.django_db(transaction=True)
def test_post_save_signal(make_user):
    user = make_user()
    assert EmailLog.objects.filter(user=user).exists()

@pytest.fixture(scope="session")
def engine():
    from sqlalchemy import create_engine
    return create_engine(TEST_DATABASE_URL)

@pytest.fixture(scope="session")
def tables(engine):
    Base.metadata.create_all(engine)
    yield
    Base.metadata.drop_all(engine)

@pytest.fixture
def db_session(engine, tables):
    connection = engine.connect()
    transaction = connection.begin()
    session = Session(bind=connection)
    yield session
    session.close()
    transaction.rollback()
    connection.close()

# conftest.py
@pytest.fixture(scope="session")
def django_db_setup(worker_id, django_test_environment, django_db_blocker):
    """Create separate DB per xdist worker."""
    from django.conf import settings
    if worker_id == "master":
        db_name = "test_mydb"
    else:
        db_name = f"test_mydb_{worker_id}"
    settings.DATABASES["default"]["NAME"] = db_name
    with django_db_blocker.unblock():
        from django.test.utils import setup_databases
        setup_databases(verbosity=0, interactive=False)
